const agentOutput = $input.first().json.output || '';

const today = new Date();
const dateStr = today.toLocaleDateString('en-US', {
  month: 'long',
  day: 'numeric',
  year: 'numeric'
});

return [{
  json: {
    subject: `Daily Paid Acquisition Report - ${dateStr}`,
    htmlBody: agentOutput
  }
}];
